POST /v1/payments
Headers: Authorization: Bearer <api_key> (required); Idempotency-Key: <uuid> (optional)
Body: { amount:int(minor units,required), currency:string(ISO-4217,required), source:string(token,required), description:string(optional) }
201: { id, status:pending|succeeded|failed, amount, currency, created_at }
Errors: 400 invalid_request, 401 unauthorized, 402 card_declined, 409 idempotency_conflict
